// ===== TopWorstSellers.js =====
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';

// Import category icons
import beerIcon from './Icons/beer.svg';
import cocktailIcon from './Icons/cocktail.svg';
import coffeeIcon from './Icons/coffee.svg';
import juicesIcon from './Icons/juices.svg';
import mocktailsIcon from './Icons/mocktails.svg';
import softdrinksIcon from './Icons/softdrinks.svg';
import spiritsIcon from './Icons/spirits.svg';
import sportdrinksIcon from './Icons/sportdrinks.svg';
import teaIcon from './Icons/tea.svg';
import wineIcon from './Icons/wine.svg';

// Import highlight icons
import highMarginIcon from './Icons/highmargin.svg';
import trendingIcon   from './Icons/trending.svg';
import ecoIcon        from './Icons/ecofriendly.svg';
import summerIcon     from './Icons/summer.svg';
import winterIcon     from './Icons/winter.svg';
import autumnIcon     from './Icons/autumn.svg';
import springIcon     from './Icons/spring.svg';

// Import location icons
import localIcon      from './Icons/locallyproduced.svg';
import nationalIcon   from './Icons/madeinbelgium.svg';
import globalIcon     from './Icons/globallysourced.svg';

// Map category names to icons
const categoryIconMap = {
    Beer: beerIcon,
    Cocktail: cocktailIcon,
    Coffee: coffeeIcon,
    Juices: juicesIcon,
    Mocktails: mocktailsIcon,
    'Soft Drinks': softdrinksIcon,
    Spirits: spiritsIcon,
    'Sport/Energy Drinks': sportdrinksIcon,
    'Tea & Infusions': teaIcon,
    Wine: wineIcon
};

// Map season to icons
const seasonIconMap = {
    Summer: summerIcon,
    Winter: winterIcon,
    Autumn: autumnIcon,
    Spring: springIcon
};

const TopWorstSellers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [businessLoc, setBusinessLoc] = useState({ city: '', country: '' });
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    // Fetch business location then sales
    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            try {
                // get business location
                const bizRes = await axios.get('http://localhost:3007/api/business-info', { withCredentials: true });
                setBusinessLoc({ city: bizRes.data.city, country: bizRes.data.country });
                // fetch sales
                const res = await axios.get('http://localhost:3007/api/sales', { withCredentials: true });
                const mapped = res.data.map(i => ({
                    id:            i.id_menu_item,
                    name:          i.item_name,
                    count:         i.total_sold ?? i.sold_count,
                    category:      i.category,
                    high_margin:   i.is_high_margin === 1,
                    trending:      i.is_trending === 1,
                    eco_friendly:  i.eco_friendly === 'Yes' || i.eco_friendly === 1,
                    season:        i.season || 'Unknown',
                    city:          i.production_city,
                    country:       i.production_country
                }));
                setItems(mapped);
            } catch (e) {
                console.error(e);
                setError('Kon verkoopcijfers niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    // Sort & filter by search term
    const sorted = [...items].sort((a, b) =>
        sortOrder === 'top' ? b.count - a.count : a.count - b.count
    );
    const visible = sorted.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    // Determine location icon per item
    const getLocationIcon = item => {
        if (item.city === businessLoc.city) return localIcon;
        if (item.country === businessLoc.country) return nationalIcon;
        return globalIcon;
    };

    return (
        <div className="top-worst-container">
            <div className="centre-content">
                <div className="segment-section">
                    <h2 className="section-title">Top & Worst</h2>
                </div>
                <div className="items-section">
                    <div className="list-header">
                        <div className="header-title">
                            <p>Top & Worst</p>
                            <h2 className="section-title">Menu-items</h2>
                        </div>
                        <div className="section-order">
                            <span className={`order-button ${sortOrder==='top'?'active':''}`} onClick={() => setSortOrder('top')}>Top sellers ↑</span>
                            <span className={`order-button ${sortOrder==='worst'?'active':''}`} onClick={() => setSortOrder('worst')}>Worst sellers ↓</span>
                        </div>
                        <div className="search-bar">
                            <input type="text" placeholder="Search" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                        </div>
                    </div>
                    <ul className="items-list">
                        {visible.map((item, idx) => (
                            <li key={item.id} className="item">
                                <div className="item-main">
                                    <span className="item-rank">{idx + 1}.</span>
                                    <span className="item-name">{item.name}</span>
                                    <div className="item-icons">
                                        {item.category && categoryIconMap[item.category] && <img src={categoryIconMap[item.category]} alt={item.category} title={item.category} className="category-icon" />}
                                        {item.high_margin && <img src={highMarginIcon} alt="High Margin" title="High Margin" className="highlight-icon" />}
                                        {item.trending    && <img src={trendingIcon   } alt="Trending"      title="Trending"      className="highlight-icon" />}
                                        {item.eco_friendly && <img src={ecoIcon        } alt="Eco Friendly"  title="Eco Friendly"  className="highlight-icon" />}
                                        {item.season!=='Unknown' && seasonIconMap[item.season] && <img src={seasonIconMap[item.season]} alt={item.season} title={item.season} className="highlight-icon" />}
                                        <img src={getLocationIcon(item)} alt="Production Location" title="Production Location" className="location-icon" />
                                    </div>
                                </div>
                                <span className="item-count">{item.count} sold</span>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
            <Optionbar />
        </div>
    );
};

export default TopWorstSellers;
